// ================================================================
// WF-3 · FEEDBACK — turns your clicks into learning.
//  used      → quality 0.9, becomes a retrieval example
//  edited    → stores your final text, measures edit distance,
//              Haiku diffs original vs final → ban candidates &
//              preferences; phrases removed in 3+ edits get
//              PROMOTED to learned_bans automatically
//  discarded → quality 0.1, excluded from retrieval
// ================================================================

const helpers = this.helpers;
const payload = $json.body || {};
if (payload.secret !== $env.LINKUP_SECRET) {
  throw new Error('Unauthorized — wrong or missing secret');
}
const exampleId = payload.example_id;
const action = payload.action;         // 'used' | 'edited' | 'discarded'
const finalText = String(payload.final_text || '');
if (!exampleId || !action) throw new Error('example_id and action are required');

// ---------- helpers (same pattern as WF-1) ----------
async function askClaude(model, maxTokens, temperature, systemPrompt, userPrompt) {
  let res;
  try {
    res = await helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': $env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json',
      },
      body: JSON.stringify({
        model, max_tokens: maxTokens, temperature,
        system: systemPrompt || undefined,
        messages: [{ role: 'user', content: userPrompt }],
      }),
    });
  } catch (e) {
    const detail = (e.response && e.response.data) ? JSON.stringify(e.response.data) : e.message;
    throw new Error('CLAUDE call failed: ' + detail);
  }
  if (typeof res === 'string') res = JSON.parse(res);
  const tb = (res.content || []).find((b) => b.type === 'text');
  if (!tb || !tb.text) throw new Error('Unexpected Claude reply: ' + JSON.stringify(res).slice(0, 400));
  return tb.text;
}
function extractJson(text) {
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('No JSON in Claude reply: ' + text.slice(0, 200));
  return JSON.parse(m[0]);
}
async function supabase(method, path, body, extraHeaders) {
  let res;
  try {
    res = await helpers.httpRequest({
      method,
      url: $env.SUPABASE_URL + path,
      headers: {
        apikey: $env.SUPABASE_SERVICE_KEY,
        Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
        'content-type': 'application/json',
        ...(extraHeaders || {}),
      },
      body: body === undefined ? undefined : JSON.stringify(body),
    });
  } catch (e) {
    const detail = (e.response && e.response.data) ? JSON.stringify(e.response.data) : e.message;
    throw new Error('SUPABASE call failed (' + method + ' ' + path + '): ' + detail);
  }
  if (typeof res === 'string' && res.trim().length) res = JSON.parse(res);
  return res;
}

// Character-level edit distance (two-row Levenshtein — fine for message-sized text)
function editDistance(a, b) {
  a = a.slice(0, 2000); b = b.slice(0, 2000);
  let prev = Array.from({ length: b.length + 1 }, (_, j) => j);
  for (let i = 1; i <= a.length; i++) {
    const cur = [i];
    for (let j = 1; j <= b.length; j++) {
      cur[j] = Math.min(
        prev[j] + 1,                                   // delete
        cur[j - 1] + 1,                                // insert
        prev[j - 1] + (a[i - 1] === b[j - 1] ? 0 : 1)  // substitute
      );
    }
    prev = cur;
  }
  return prev[b.length];
}

// ---------- load the example + voice profile ----------
const exRows = await supabase('GET', '/rest/v1/message_examples?id=eq.' + exampleId + '&select=*');
if (!exRows.length) throw new Error('message_example not found: ' + exampleId);
const ex = exRows[0];
const vp = (await supabase('GET', '/rest/v1/voice_profile?id=eq.1&select=*'))[0];

const vpPatch = { updated_at: new Date().toISOString() };
let exPatch = {};
let learnedNote = '';

if (action === 'used') {
  exPatch = { outcome: 'used_as_is', draft_sent: ex.draft_original,
              edit_distance: 0, quality_score: 0.9 };
  vpPatch.drafts_used_as_is = (vp.drafts_used_as_is || 0) + 1;

} else if (action === 'discarded') {
  exPatch = { outcome: 'discarded', quality_score: 0.1 };

} else if (action === 'edited') {
  const d = editDistance(ex.draft_original, finalText);
  exPatch = {
    outcome: d < 20 ? 'edited_minor' : 'edited_heavy',
    draft_sent: finalText,
    edit_distance: d,
    quality_score: d < 20 ? 0.7 : 0.4,
  };
  vpPatch.drafts_edited = (vp.drafts_edited || 0) + 1;

  // ---- learn from the diff (Haiku, temp 0) ----
  const diffPrompt = `Compare Sagnik's ORIGINAL AI draft with his EDITED final version.
Identify STYLISTIC changes only (wording/phrasing), not factual ones.
Return ONLY JSON:
{"removed_phrases": string[],   // 2-6 word phrases he deleted or replaced
 "preferred_rewrites": [{"from": string, "to": string}]}  // phrasings he changed
Return empty arrays if the changes are purely factual.

ORIGINAL:
${ex.draft_original}

EDITED FINAL:
${finalText}`;
  const diff = extractJson(await askClaude('claude-haiku-4-5-20251001', 400, 0, null, diffPrompt));

  // Ban candidates: count removals; promote to learned_bans at 3 strikes.
  const candidates = Object.assign({}, vp.ban_candidates || {});
  const bans = new Set(vp.learned_bans || []);
  (diff.removed_phrases || []).forEach((p) => {
    const key = p.trim().toLowerCase();
    if (!key || key.length < 4) return;
    candidates[key] = (candidates[key] || 0) + 1;
    if (candidates[key] >= 3) { bans.add(key); learnedNote += ' Ban promoted: "' + key + '".'; }
  });
  // Preferences: remember the rewrite immediately (advisory, low risk).
  const prefs = Object.assign({}, vp.learned_preferences || {});
  (diff.preferred_rewrites || []).forEach((r) => {
    if (r && r.from && r.to) prefs[r.from.trim().toLowerCase()] = r.to.trim();
  });
  vpPatch.ban_candidates = candidates;
  vpPatch.learned_bans = Array.from(bans);
  vpPatch.learned_preferences = prefs;
}

await supabase('PATCH', '/rest/v1/message_examples?id=eq.' + exampleId, exPatch);
await supabase('PATCH', '/rest/v1/voice_profile?id=eq.1', vpPatch);

return [{ json: { ok: true, outcome: exPatch.outcome,
                  edit_distance: exPatch.edit_distance || 0,
                  note: learnedNote.trim() || undefined } }];
